import (
	"fmt"
	"sync"
)

func reshelf(section string, wg *sync.WaitGroup) {
	defer wg.Done()
	fmt.Printf("Section %s reshelved\n", section)
}

func main() {
	var wg sync.WaitGroup

	for _, s := range []string{"A", "B", "C"} {
		wg.Add(1)
		go reshelf(s, &wg)
	}

	wg.Wait()
	fmt.Println("All sections complete — library ready")
}

