package main

import (
	"fmt"
	"sync"
)

type LibraryCounter struct {
	mu    sync.Mutex
	count int
}

func (c *LibraryCounter) CheckOut() {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.count++
}

func (c *LibraryCounter) Total() int {
	c.mu.Lock()
	defer c.mu.Unlock()
	return c.count
}

func main() {
	counter := &LibraryCounter{}
	var wg sync.WaitGroup

	for i := 0; i < 100; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			counter.CheckOut()
		}()
	}

	wg.Wait()
	fmt.Println("Total check-outs:", counter.Total())
}

package main

import (
	"fmt"
	"time"
)

func shelver(done <-chan struct{}) {
	for {
		select {
		case <-done:
			fmt.Println("Shelver: heading home")
			return
		default:
			fmt.Println("Shelver: organizing shelves...")
			time.Sleep(20 * time.Millisecond)
		}
	}
}

func main() {
	done := make(chan struct{})
	go shelver(done)
	time.Sleep(60 * time.Millisecond)
	close(done)
	time.Sleep(30 * time.Millisecond)
	fmt.Println("Main: library closed")
}

package main

import (
	"fmt"
	"sync"
)

func librarian(id int, jobs <-chan int, results chan<- int, wg *sync.WaitGroup) {
	defer wg.Done()
	for j := range jobs {
		results <- j * j
		fmt.Printf("Librarian %d helped with query %d\n", id, j)
	}
}

func main() {
	jobs := make(chan int, 12)
	results := make(chan int, 12)
	var wg sync.WaitGroup

	for w := 1; w <= 3; w++ {
		wg.Add(1)
		go librarian(w, jobs, results, &wg)
	}

	for i := 1; i <= 9; i++ {
		jobs <- i
	}
	// TODO: add jobs 10, 11, 12
	close(jobs)

	wg.Wait()
	close(results)

	total := 0
	for r := range results {
		total += r
	}
	fmt.Println("Total queries answered:", total)
}

